import{_ as t,o as r,c as o,a2 as a}from"./chunks/framework.B8zgMDLd.js";const u=JSON.parse('{"title":"Properties","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/properties.md","filePath":"concepts/properties.md"}'),i={name:"concepts/properties.md"};function d(s,e,p,n,c,l){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h1><p>Properties are frontmatter fields that Tolaria can display, filter, and edit.</p><h2 id="suggested-properties" tabindex="-1">Suggested Properties <a class="header-anchor" href="#suggested-properties" aria-label="Permalink to &quot;Suggested Properties&quot;">​</a></h2><p>Suggested properties are the fields Tolaria knows how to create quickly from the Properties panel. When a suggested property is missing, the panel shows a shortcut to add it with the right editor.</p><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th></tr></thead><tbody><tr><td><code>type</code></td><td>Groups the note into a type such as Project, Person, or Topic.</td></tr><tr><td><code>status</code></td><td>Tracks lifecycle state such as Active, Done, or Blocked.</td></tr><tr><td><code>url</code></td><td>Stores a canonical external link.</td></tr><tr><td><code>date</code></td><td>Represents a single date.</td></tr></tbody></table><h2 id="system-properties" tabindex="-1">System Properties <a class="header-anchor" href="#system-properties" aria-label="Permalink to &quot;System Properties&quot;">​</a></h2><p>Fields that start with <code>_</code> are system properties. They remain in plain text but are hidden from normal property editing.</p><p>Examples include <code>_icon</code>, <code>_color</code>, <code>_order</code>, <code>_sidebar_label</code>, <code>_width</code>, and <code>_pinned_properties</code> on type documents or notes.</p><h2 id="property-editing" tabindex="-1">Property Editing <a class="header-anchor" href="#property-editing" aria-label="Permalink to &quot;Property Editing&quot;">​</a></h2><p>The Properties panel is the safest place to edit structured properties. Toggle it with <code>Cmd+Shift+I</code> on macOS or <code>Ctrl+Shift+I</code> on Windows and Linux.</p><p>Date fields use Tolaria&#39;s picker, relationship fields can use wikilinks, and raw Markdown mode is available when you need direct control over YAML.</p>',11)])])}const _=t(i,[["render",d]]);export{u as __pageData,_ as default};
